function loadDeviceImageParams(deviceIp) {
    if (!deviceIp) return;

    if (typeof apiGet === 'undefined') {
        console.error('[IMAGE] apiGet not defined');
        return;
    }

    console.log('[IMAGE] Loading image params for:', deviceIp);

    // v6.20: 重置状态
    functionCacheLoaded = false;
    deviceFunctionData = null;

    // v6.20: 使用 async/await 确保顺序但不阻塞 UI
    (async function() {
        // 1. 先尝试加载 function.json 缓存
        try {
            var r = await apiGet('/api/v1/ptz/' + deviceIp + '/function');
            if (r && r.success && r.data && r.data.results) {
                deviceFunctionData = r.data;
                functionCacheLoaded = true;
                console.log('[IMAGE] function.json loaded from cache');
                enableImageControls();
            } else {
                console.warn('[IMAGE] function.json not found or invalid');
                disableImageControls('未完成功能测试');
                functionCacheLoaded = false;
                return; // 无缓存，不加载其他参数
            }
        } catch (e) {
            console.warn('[IMAGE] function.json failed:', e);
            disableImageControls('未完成功能测试');
            functionCacheLoaded = false;
            return;
