    for key, dev in ptz_cfg.get("devices", {}).items():
        if dev.get("ip") == ip:
            dev["connected"] = False
            self.config.save_ptz_config(ptz_cfg)
            break

    # v6.20: 清除 registry.json 的 active_device
    import json
    if self._registry_file.exists():
        try:
            registry = json.loads(self._registry_file.read_text(encoding='utf-8'))
            # 如果当前断开的设备是活跃设备，清除 active_device
            if registry.get('active_device') == key:
