def _parse_sadp_response(data: bytes) -> SADPDevice | None:
    """���� SADP ��Ӧ XML��

    SADP ��Ӧ��ʽ�����ǣ�
    1. �� XML: <?xml...?><DeviceProbe>...</DeviceProbe>
    2. Binary header + XML: 4��8�ֽ� header + XML
       - v2: \x00\x00\x00\x00 �� \xFF\xFF\xFF\xFF + 4�ֽڴ�˳��� + XML
       - v3: "usdp" + 4�ֽڴ�˳��� + XML
    """
    try:
        text = None
        xml_str = None

        # ---- ����1������ֱ����Ϊ XML ----
        raw_text = data.decode("utf-8", errors="ignore")
        if "<DeviceProbe>" in raw_text or "<sadpDeviceInfo>" in raw_text or "<?xml" in raw_text:
            text = raw_text

        # ---- ����2���������� binary header ----
        if text is None and len(data) > 8:
            # ����Ƿ��� known magic bytes
            has_magic = False
            if data[:4] == b"usdp":
                has_magic = True
            elif data[:4] in (b"\x00\x00\x00\x00", b"\xff\xff\xff\xff"):
                has_magic = True
            elif data[:4] in (b"\x00\x00\x00\x01",):
                has_magic = True

            if has_magic:
                # ���Դ� binary data ����ȡ XML
                # ���� header (4��8�ֽ�)���� XML
                for start_offset in [4, 8, 10, 12]:
                    if start_offset < len(data):
                        chunk = data[start_offset:].decode("utf-8", errors="ignore")
