            return None

        # �ҵ� XML ��ʼλ��
        xml_start = text.find("<DeviceProbe>")
        if xml_start < 0:
            xml_start = text.find("<sadpDeviceInfo>")
        if xml_start < 0:
            xml_start = text.find("<?xml")
        if xml_start < 0:
            LOG.log("warning", f"SADP ��Ӧ���� XML: {repr(text[:200])}")
