        LOG.log("warning", "���˵��� Python �ಥ...")
        return _scan_via_multicast(bind_ip="0.0.0.0")


def _scan_via_multicast(bind_ip: str = "0.0.0.0") -> list[SADPDevice]:
    """�� Python �ಥ���÷���."""
    actual_ip = _get_local_ip()  # ��ȡ������ʵ IP ���ڶಥ�ӿڰ�
    devices: list[SADPDevice] = []
    seen_macs: set[str] = set()
    uuid_str = uuid.uuid4().hex
    probe = f"""<?xml version="1.0" encoding="UTF-8"?>
<Probe><Uuid>{uuid_str}</Uuid><Types>inquiry</Types></Probe>""".encode("utf-8")

    # �ؼ������� socket �󶨵� SADP_PORT���ȷ����ֽ���
    sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM, socket.IPPROTO_UDP)
    sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
    # Windows SO_REUSEPORT
    if platform.system() == "Windows":
        try:
            sock.setsockopt(socket.SOL_SOCKET, 0x18, 1)
        except Exception:
            pass

    try:
        sock.bind(("", SADP_PORT))
        LOG.log("info", f"Socket �Ѱ󶨵� 0.0.0.0:{SADP_PORT}")
    except OSError as e:
        LOG.log("warning", f"�� 0.0.0.0:{SADP_PORT} ʧ��: {e}, ���Ա��÷���...")
        sock.close()
        sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM, socket.IPPROTO_UDP)
        sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
        sock.bind(("", SADP_PORT))
        LOG.log("info", f"���÷����󶨳ɹ�: 0.0.0.0:{SADP_PORT}")

    # ����ಥ��
    try:
        mreq = struct.pack("4s4s", socket.inet_aton(SADP_MULTICAST_ADDR), socket.inet_aton(actual_ip))
        sock.setsockopt(socket.IPPROTO_IP, socket.IP_ADD_MEMBERSHIP, mreq)
        LOG.log("info", f"�Ѽ���ಥ�� {SADP_MULTICAST_ADDR} via {actual_ip}")
    except Exception as e:
        LOG.log("warning", f"����ಥ��ʧ��: {e}")

    try:
        # ---- ����̽�ⱨ�ģ��ؼ����󶨵� SADP_PORT ���豸 unicast ������˿ڣ�----
        send_sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM, socket.IPPROTO_UDP)
        try:
            send_sock.setsockopt(socket.SOL_SOCKET, socket.SO_REUSEADDR, 1)
            if platform.system() == "Windows":
                try:
                    send_sock.setsockopt(socket.SOL_SOCKET, 0x18, 1)
                except Exception:
                    pass
            send_sock.bind(("", SADP_PORT))
            send_sock.setsockopt(socket.IPPROTO_IP, socket.IP_MULTICAST_TTL, 2)
            send_sock.setsockopt(socket.IPPROTO_IP, socket.IP_MULTICAST_IF, socket.inet_aton(actual_ip))
            LOG.log("info", f"���� socket �󶨵� :{SADP_PORT}, ���ͽӿ�: {actual_ip}")
            for i in range(3):
                send_sock.sendto(probe, (SADP_MULTICAST_ADDR, SADP_PORT))
                LOG.log("info", f"SADP probe #{i+1} �ѷ��� to {SADP_MULTICAST_ADDR}:{SADP_PORT}")
                time.sleep(1)
        except Exception as e:
            import traceback
            LOG.log("error", f"SADP �����쳣: {e}")
            LOG.log("error", f"���Ͷ�ջ: {traceback.format_exc()}")
        finally:
            send_sock.close()
            LOG.log("info", "���� socket �ѹر�")

        # ---- ������Ӧ ----
        LOG.log("info", "��ʼ������Ӧ...")
        sock.settimeout(0.5)
        timeout_at = time.time() + (SADP_TIMEOUT_MS / 1000.0)
        while time.time() < timeout_at:
            try:
                data, addr = sock.recvfrom(65535)
                LOG.log("info", f"�յ� [{len(data)}B] from {addr[0]}:{addr[1]}")
                try:
                    raw = data.decode("utf-8", errors="ignore")[:400]
                    LOG.log("info", f"ԭʼ����: {raw}")
                except Exception:
                    LOG.log("info", f"ʮ������: {data[:200].hex()}")
                device = _parse_sadp_response(data)
                if device:
                    LOG.log("info", f"�����ɹ�: MAC={device.mac} IP={device.ip} model={device.model}")
                if device and device.mac and device.mac not in seen_macs:
                    seen_macs.add(device.mac)
                    devices.append(device)
                    LOG.log("done", f"�����豸: {device.display_name()} IP={device.ip}")
            except socket.timeout:
                continue

    finally:
        try:
            sock.setsockopt(socket.IPPROTO_IP, socket.IP_DROP_MEMBERSHIP,
                            struct.pack("4s4s", socket.inet_aton(SADP_MULTICAST_ADDR), socket.inet_aton(actual_ip)))
        except Exception:
            pass
        sock.close()
        LOG.log("info", "���� socket �ѹر�")

    LOG.log("info", f"SADP ɨ�����: ���� {len(devices)} ̨�豸")
    for d in devices:
        LOG.log("info", f"  MAC={d.mac} IP={d.ip} model={d.model} ����={d.activated}")

    hikvision_devices = [d for d in devices if d.is_hikvision]
    if hikvision_devices:
        return hikvision_devices
    if devices:
        LOG.log("warning", f"���� {len(devices)} ̨�豸���� Hikvision OUI ƥ�䣬�Է���ȫ��")
    return devices

