            sdk_devices = mgr.discover_devices(timeout=3)
            if sdk_devices:
                LOG.log("done", f"SADP SDK ���� {len(sdk_devices)} ̨�豸")
                result = []
                for dev_dict in sdk_devices:
                    # ת��Ϊ SADPDevice dataclass �Ա���������
                    dev = SADPDevice()
