    def remove_credentials(self, ip: str) -> bool:
        """�Ƴ��豸ƾ�ݡ�"""
        self._credentials.pop(ip, None)
        # ��������Ҳ�Ƴ�
        config = self.config.load_ptz_config()
        devices = config.get("devices", {})
        # ͨ�� IP �� MAC ����
        for key, dev in list(devices.items()):
