        config = self.config.load_ptz_config()
        devices = config.get("devices", {})
        result = []
        for mac, info in devices.items():
            ip = info.get("ip", "")
            is_connected = ip in self._controllers
            sadp_info = self._discovered.get(mac)
            entry = {
